function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

async function exchangeToken(appId, secretKey, code) {
  const form = new URLSearchParams({
    app_id: String(appId || ''),
    code: String(code || ''),
    grant_type: 'authorization_code',
  });

  const response = await fetch('https://oauth.zaloapp.com/v4/oa/access_token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      secret_key: String(secretKey || ''),
    },
    body: form.toString(),
  });

  const raw = await response.text();
  let payload;
  try {
    payload = JSON.parse(raw);
  } catch {
    payload = { raw };
  }

  return {
    status: response.status,
    ok: response.ok,
    payload,
  };
}

const input = $input.first().json || {};
const query = input.query || {};
const code = String(query.code || '');
const error = String(query.error || query.error_code || '');
const errorDescription = String(query.error_description || query.error_reason || '');
const appId = String($vars.ZALO_APP_ID || '1450975846052622442');
const secretKey = String($vars.ZALO_OA_SECRET_KEY || $vars.ZALO_APP_SECRET || '');
const redirectUrl = String(input.webhookUrl || '');

let ok = false;
let title = 'CaloTrack Zalo OA token callback';
let summary = '';
let tokenPayload = {};
let accessToken = '';
let refreshToken = '';
let expiresIn = 0;
let expiresAt = '';

if (error) {
  title = 'Zalo OA permission failed';
  summary = `Zalo tra ve loi: ${error}${errorDescription ? ` - ${errorDescription}` : ''}`;
} else if (!code) {
  title = 'Missing authorization code';
  summary = 'Khong tim thay query param code tren callback URL.';
} else if (!secretKey) {
  title = 'Missing Zalo secret in n8n';
  summary = 'Can set ZALO_OA_SECRET_KEY hoac ZALO_APP_SECRET trong n8n Variables truoc khi doi token.';
} else {
  const result = await exchangeToken(appId, secretKey, code);
  tokenPayload = result.payload || {};
  accessToken = String(tokenPayload.access_token || tokenPayload.accessToken || '');
  refreshToken = String(tokenPayload.refresh_token || tokenPayload.refreshToken || '');
  expiresIn = Number(tokenPayload.expires_in || tokenPayload.expires || 0) || 0;
  expiresAt = expiresIn > 0 ? new Date(Date.now() + (expiresIn * 1000)).toISOString() : '';
  ok = Boolean(result.ok && accessToken);

  if (ok) {
    title = 'Zalo OA token ready';
    summary = 'Da doi code sang access token thanh cong. Hay copy cac gia tri ben duoi vao n8n Variables.';
  } else {
    title = 'Zalo OA token exchange failed';
    summary = `Zalo tra ve HTTP ${result.status}. Kiem tra lai redirect URI, secret key va OA permission.`;
  }
}

const responseJson = {
  ok,
  title,
  summary,
  app_id: appId,
  redirect_url: redirectUrl,
  access_token: accessToken,
  refresh_token: refreshToken,
  expires_in: expiresIn,
  expires_at: expiresAt,
  token_payload: tokenPayload,
};

const html = `<!DOCTYPE html>
<html lang="vi">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${escapeHtml(title)}</title>
  <style>
    body { font-family: Inter, Arial, sans-serif; background: #f4fbfa; color: #17203a; padding: 40px 20px; }
    .card { max-width: 880px; margin: 0 auto; background: #ffffff; border: 1px solid #d7ece8; border-radius: 24px; padding: 28px; box-shadow: 0 20px 60px rgba(23, 32, 58, 0.08); }
    .badge { display: inline-block; padding: 6px 12px; border-radius: 999px; font-size: 12px; letter-spacing: 0.12em; text-transform: uppercase; background: ${ok ? '#d9f5ef' : '#fff3e8'}; color: ${ok ? '#0f766e' : '#b45309'}; }
    h1 { margin: 16px 0 8px; font-size: 34px; }
    p { line-height: 1.6; color: #4f5d78; }
    pre { white-space: pre-wrap; word-break: break-word; background: #f7fafc; border: 1px solid #dde6f0; border-radius: 16px; padding: 16px; font-size: 13px; overflow: auto; }
    .grid { display: grid; gap: 14px; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); margin-top: 22px; }
    .panel { background: #fbfdff; border: 1px solid #e8eef5; border-radius: 18px; padding: 16px; }
    .panel h2 { margin: 0 0 12px; font-size: 14px; letter-spacing: 0.08em; text-transform: uppercase; color: #0f766e; }
    .mono { font-family: Consolas, monospace; }
  </style>
</head>
<body>
  <div class="card">
    <span class="badge">${ok ? 'success' : 'needs action'}</span>
    <h1>${escapeHtml(title)}</h1>
    <p>${escapeHtml(summary)}</p>
    <div class="grid">
      <div class="panel">
        <h2>n8n Variables</h2>
        <pre class="mono">ZALO_APP_ID=${escapeHtml(appId)}
ZALO_OA_SECRET_KEY=(rotate va set secret moi)
ZALO_OA_ACCESS_TOKEN=${escapeHtml(accessToken)}
ZALO_OA_REFRESH_TOKEN=${escapeHtml(refreshToken)}
ZALO_OA_TOKEN_EXPIRES_AT=${escapeHtml(expiresAt)}</pre>
      </div>
      <div class="panel">
        <h2>Debug</h2>
        <pre class="mono">redirect_url=${escapeHtml(redirectUrl)}
code=${escapeHtml(code)}
expires_in=${escapeHtml(expiresIn)}</pre>
      </div>
    </div>
    <div class="panel" style="margin-top: 18px;">
      <h2>Token payload</h2>
      <pre class="mono">${escapeHtml(JSON.stringify(responseJson, null, 2))}</pre>
    </div>
  </div>
</body>
</html>`;

return [{ json: { ...responseJson, html } }];
